import sys
from functools import lru_cache
input_data = sys.stdin.read().split()
n = int(input_data[0])
A = list(map(int, input_data[1:n+1]))

@lru_cache(maxsize=None)
def wins(l, r, last):
    if l > r:
        return False
    can_left = A[l] > last
    can_right = A[r] > last
    if not can_left and not can_right:
        return False
    if can_left and wins(l+1, r, A[l]) == False:
        return True
    if can_right and wins(l, r-1, A[r]) == False:
        return True
    return False

result = wins(0, n-1, -1)
print("Alice" if result else "Bob")

